const fs = require('fs');
const path = require('path');
const ROOT = process.cwd();

const spineFiles = [
  'startup/register-runtime-routes.js',
  'startup/routes/server-routes.js',
  'core/two-tier-system-init.js',
  'server.js',
  'startup/boot-domains.js',
].map((f) => fs.readFileSync(f, 'utf8')).join('\n');

const inventory = fs.readFileSync('docs/SYSTEM_CAPABILITY_INVENTORY.md', 'utf8');
const rowRe = /^\| ([^|]+?) \| `(PRESENT|PARTIAL|MISSING|SHADOW)` \| ([^|]+?) \|/gm;
const rows = [];
let m;
while ((m = rowRe.exec(inventory))) {
  rows.push({ name: m[1].trim(), inv: m[2], files: m[3].trim() });
}

function extractPaths(text) {
  return [...text.matchAll(/`([^`]+\.(?:js|mjs|sql|md))`/g)].map((x) => x[1].split(',')[0].trim());
}

function exists(rel) {
  if (!rel || rel.includes('*')) return null;
  const p = path.join(ROOT, rel.replace(/^\.\//, ''));
  return fs.existsSync(p);
}

function mounted(rel) {
  if (!rel) return false;
  const base = path.basename(rel);
  return spineFiles.includes(base) || spineFiles.includes(rel);
}

function hasTest(rel) {
  if (!rel) return false;
  const base = path.basename(rel, path.extname(rel));
  const testsDir = path.join(ROOT, 'tests');
  if (!fs.existsSync(testsDir)) return false;
  for (const f of fs.readdirSync(testsDir)) {
    if (f.includes(base.replace(/-routes$/, '').replace(/-service$/, ''))) return true;
  }
  const scripts = fs.readdirSync(path.join(ROOT, 'scripts')).filter((f) => f.includes('verify') || f.includes('proof') || f.includes('acceptance'));
  const slug = base.replace(/\.js$/, '').replace(/-routes$/, '');
  return scripts.some((s) => s.includes(slug.split('-')[0]) && s.includes(slug.split('-').slice(-1)[0]));
}

const statusCounts = {};
const audited = rows.map((r) => {
  const paths = extractPaths(r.files);
  const primary = paths.find((p) => p.startsWith('routes/') || p.startsWith('services/') || p.startsWith('scripts/')) || paths[0];
  const ex = primary ? exists(primary) : null;
  const mount = paths.some(mounted);
  const test = paths.some(hasTest);

  let status;
  if (r.inv === 'MISSING') status = 'MISSING';
  else if (r.inv === 'SHADOW') status = 'REJECT';
  else if (ex === false) status = 'MISSING';
  else if (ex === null && r.inv === 'MISSING') status = 'MISSING';
  else if (!mount && ex && (primary?.startsWith('routes/') || r.name.toLowerCase().includes('routes'))) status = 'BUILT BUT DISCONNECTED';
  else if (r.inv === 'PARTIAL') status = 'PARTIAL';
  else if (mount && ex) status = 'ACTIVE';
  else if (ex && !mount) status = 'BUILT BUT DISCONNECTED';
  else status = 'UNVERIFIED';

  // manual overrides from repo evidence
  const overrides = {
    'Continuous queue (shadow queue)': 'REJECT',
    'Builder continuous queue': 'REJECT',
    'Product development gate': 'MISSING',
    'Determinism checker at Builder tier': 'PARTIAL',
    'TSOS task ledger': 'BUILT BUT DISCONNECTED',
    'Sleep': 'BUILT BUT DISCONNECTED',
    'Conflict interrupt': 'BUILT BUT DISCONNECTED',
    'Decision review': 'BUILT BUT DISCONNECTED',
    'Marketing routes': 'BUILT BUT DISCONNECTED',
    'BoldTrail real estate': 'PARTIAL',
    'Workshop of mind': 'ACTIVE',
    'Copilot': 'ACTIVE',
    'Simulator': 'ACTIVE',
    'Command center aggregate': 'ACTIVE',
    'Historical server.js analysis': 'ARCHIVE',
    'Legacy prompts (pre-2026)': 'ARCHIVE',
    'Old self-programming path': 'LEGACY',
    'Old self-improvement loop': 'LEGACY',
    'Orphan routes (CJS in ESM, not imported)': 'LEGACY',
    'Autonomous efficiency intelligence': 'LEGACY',
    'ChatGPT import': 'LEGACY',
    'Email provision (Postmark)': 'PARTIAL',
    'Native mobile mic (iOS/Android)': 'MISSING',
    'Wearable integration': 'PARTIAL',
    'User auth (multi-user)': 'PARTIAL',
    'Historian canonical contract (NSSOT §2.0I)': 'PARTIAL',
    'Fraud detection': 'PARTIAL',
    'Document processor': 'PARTIAL',
    'Founder packet completeness checker': 'PARTIAL',
    'DONE gate — /build wiring': 'PARTIAL',
  };
  if (overrides[r.name]) status = overrides[r.name];

  statusCounts[status] = (statusCounts[status] || 0) + 1;
  return { ...r, primary, ex: ex === null ? 'UNVERIFIED' : ex ? 'Y' : 'N', mount: mount ? 'Y' : 'N', status };
});

console.log(JSON.stringify({ total: audited.length, statusCounts }, null, 2));
// output csv for doc
audited.forEach((a) => {
  console.log([a.name, a.status, a.ex, a.mount, a.inv, a.primary || ''].join('\t'));
});
