function allJsContent() {
  const dirs = ['routes', 'services', 'startup', 'core', 'scripts'];
  let content = '';
  for (const d of dirs) {
    const p = path.join(ROOT, d);
    if (!fs.existsSync(p)) continue;
    for (const f of fs.walk ? [] : walk(p)) {
      if (f.endsWith('.js') || f.endsWith('.mjs')) {
        try { content += fs.readFileSync(f, 'utf8') + '\n'; } catch {}
      }
    }
  }
  content += fs.readFileSync('server.js', 'utf8');
  return content;
}
function walk(dir, out=[]) {
  for (const ent of fs.readdirSync(dir, { withFileTypes: true })) {
    const p = path.join(dir, ent.name);
    if (ent.isDirectory()) {
      if (ent.name === 'node_modules') continue;
      walk(p, out);
    } else out.push(p);
  }
  return out;
}
const corpus = allJsContent();
const spine = ['startup/register-runtime-routes.js','startup/routes/server-routes.js','core/two-tier-system-init.js','server.js','startup/boot-domains.js']
