  'Continuous queue (shadow queue)':'REJECT','Builder continuous queue':'REJECT',
  'Product development gate':'MISSING','Native mobile mic (iOS/Android)':'MISSING',
  'TSOS task ledger':'BUILT BUT DISCONNECTED','Sleep':'BUILT BUT DISCONNECTED',
  'Conflict interrupt':'BUILT BUT DISCONNECTED','Decision review':'BUILT BUT DISCONNECTED',
  'Marketing routes':'BUILT BUT DISCONNECTED','BoldTrail real estate':'PARTIAL',
  'Historical server.js analysis':'ARCHIVE','Legacy prompts (pre-2026)':'ARCHIVE',
  'Old self-programming path':'LEGACY','Old self-improvement loop':'LEGACY',
  'Orphan routes (CJS in ESM, not imported)':'LEGACY','Autonomous efficiency intelligence':'LEGACY',
  'ChatGPT import':'LEGACY','Email provision (Postmark)':'PARTIAL','Wearable integration':'PARTIAL',
  'User auth (multi-user)':'PARTIAL','Historian canonical contract (NSSOT §2.0I)':'PARTIAL',
  'Fraud detection':'PARTIAL','Document processor':'PARTIAL','Founder packet completeness checker':'PARTIAL',
  'Determinism checker at Builder tier':'PARTIAL','Agent recruitment routes':'ACTIVE',
  'Site builder launch readiness':'ACTIVE',
};

const counts = {};
const lines = [];
for (const r of rows) {
  const paths = extractPaths(r.files);
  const primary = paths.find(p=>p.startsWith('routes/')||p.startsWith('services/')||p.startsWith('scripts/'))||paths[0];
  const ex = primary ? exists(primary) : null;
  const isRoute = primary?.startsWith('routes/');
