    else if (r.inv==='SHADOW') status='REJECT';
    else if (!ex) status='MISSING';
    else if (isRoute && !mount) status='BUILT BUT DISCONNECTED';
    else if (mount && consumer) status='ACTIVE';
    else if (consumer && ex) status='PARTIAL';
    else if (ex && !consumer) status='BUILT BUT DISCONNECTED';
    else status='UNVERIFIED';
  }

  let conf = 'LOW';
  if (status==='ACTIVE' && test) conf='HIGH';
  else if (status==='ACTIVE' || status==='PARTIAL') conf='MEDIUM';

  counts[status]=(counts[status]||0)+1;
