+    requires_agent_approval: true,
+  };
+}
+
+function extractTcFields(text) {
+  const source = ensureText(text);
+  return {
+    client_name: (source.match(/client[:\s]+([A-Za-z .'-]+)/i) || [])[1] || null,
+    property_address: (source.match(/address[:\s]+([A-Za-z0-9 .,#'-]+)/i) || [])[1] || null,
