+  if (!fs.existsSync(absPath)) return null;
+  try {
+    return JSON.parse(fs.readFileSync(absPath, 'utf8'));
+  } catch {
+    return null;
+  }
+}
+
+function writeJson(absPath, data) {
+  fs.mkdirSync(path.dirname(absPath), { recursive: true });
