+}
+
+function resolveMissionFolder(missionIdOrPath) {
+  const raw = String(missionIdOrPath || '').trim();
+  if (!raw) return null;
+  if (path.isAbsolute(raw)) return raw;
+  if (raw.includes('/')) return path.join(REPO_ROOT, raw);
+  return path.join(MISSIONS_ROOT, raw);
+}
