+  }
+  if (process.env.GEMINI_API_KEY || process.env.GOOGLE_AI_KEY) {
+    pool.push({ id: 'gemini', model: process.env.ARC_BLIND_GEMINI_MODEL || 'gemini-2.5-pro' });
+  }
+  if (process.env.OPENAI_API_KEY) {
+    pool.push({ id: 'openai', model: process.env.ARC_BLIND_OPENAI_MODEL || 'gpt-4.1' });
