+  if (provider.id === 'gemini') return callGemini(prompt, provider.model);
+  if (provider.id === 'openai') return callOpenAI(prompt, provider.model);
+  if (provider.id === 'groq') return callGroq(prompt, provider.model);
+  throw new Error(`unsupported_provider_${provider.id}`);
+}
+
+function parseJsonResponse(text) {
+  const cleaned = String(text || '')
+    .replace(/^```(?:json)?\s*/i, '')
+    .replace(/\s*```$/i, '')
+    .trim();
+  return JSON.parse(cleaned);
+}
+
+function normalizeBlueprint(bp) {
+  const steps = Array.isArray(bp?.steps) ? bp.steps : [];
+  const normalizedSteps = steps.map((s) => ({
+    phase_id: String(s.phase_id || ''),
+    target_file: String(s.target_file || ''),
+    action_type: String(s.action_type || ''),
+  }));
+  return {
+    mission_id: String(bp?.mission_id || ''),
+    step_count: normalizedSteps.length,
+    targets: normalizedSteps.map((s) => s.target_file).sort(),
+    phases: [...new Set(normalizedSteps.map((s) => s.phase_id))].sort(),
+    action_types: [...new Set(normalizedSteps.map((s) => s.action_type))].sort(),
+  };
+}
+
+function jaccard(a, b) {
+  const A = new Set(a);
+  const B = new Set(b);
+  const union = new Set([...A, ...B]);
+  if (!union.size) return 1;
+  let intersect = 0;
+  for (const x of A) if (B.has(x)) intersect += 1;
+  return intersect / union.size;
+}
+
+function compareThree(normalized) {
+  const [a, b, c] = normalized;
+  const ab = jaccard(a.targets, b.targets);
+  const ac = jaccard(a.targets, c.targets);
+  const bc = jaccard(b.targets, c.targets);
+  const average = (ab + ac + bc) / 3;
+  return {
+    pairwise_target_jaccard: { ab, ac, bc, average },
+    essentially_same: average >= 0.8,
+  };
+}
