+async function main() {
+  const missionArg = process.argv[2];
+  if (!missionArg) {
+    console.error('Usage: node scripts/run-arc-triple-blind.mjs <mission_id_or_path>');
+    process.exit(1);
+  }
+
+  const missionFolder = resolveMissionFolder(missionArg);
+  const missionId = path.basename(missionFolder);
+  if (!fs.existsSync(missionFolder)) {
+    console.error(`Mission folder not found: ${missionFolder}`);
+    process.exit(1);
+  }
+
+  const founderPacket = readText(path.join(missionFolder, 'FOUNDER_PACKET.md'));
+  const baseline = readJson(path.join(missionFolder, 'INTENT_BASELINE.json'));
+  const coverage = readJson(path.join(missionFolder, 'INTENT_COVERAGE_MAP.json'));
+  const preArcPacket = readJson(path.join(missionFolder, 'PRE_ARC_INPUT_PACKET.json'));
+
+  const prompt = buildArchitectPrompt({
+    missionId,
+    founderPacket,
+    baseline,
+    coverage,
+    preArcPacket,
+  });
