+    console.error(`Need 3 provider APIs, found ${pool.length}. Available: ${pool.map((p) => p.id).join(', ')}`);
+    process.exit(2);
+  }
+  const selected = pool.slice(0, 3);
+  const runId = `arc_blind_${Date.now()}`;
+  const outDir = path.join(missionFolder, 'receipts', 'ARC_TRIPLE_BLIND', runId);
+  fs.mkdirSync(outDir, { recursive: true });
+
+  const results = [];
+  for (let i = 0; i < selected.length; i += 1) {
+    const lane = selected[i];
+    const laneId = String.fromCharCode(65 + i); // A/B/C
+    const started = Date.now();
+    try {
+      const raw = await callProvider(lane, prompt);
+      const blueprint = parseJsonResponse(raw);
+      const normalized = normalizeBlueprint(blueprint);
+      const laneResult = {
+        lane: laneId,
+        provider: lane.id,
+        model: lane.model,
+        elapsed_ms: Date.now() - started,
+        ok: true,
+        normalized,
+      };
+      writeJson(path.join(outDir, `ARCHITECT_${laneId}_BLUEPRINT.json`), blueprint);
+      writeJson(path.join(outDir, `ARCHITECT_${laneId}_META.json`), laneResult);
+      results.push({ ...laneResult, blueprint });
+    } catch (error) {
+      const laneResult = {
+        lane: laneId,
+        provider: lane.id,
+        model: lane.model,
+        elapsed_ms: Date.now() - started,
+        ok: false,
+        error: String(error.message || error),
+      };
+      writeJson(path.join(outDir, `ARCHITECT_${laneId}_META.json`), laneResult);
+      results.push(laneResult);
+    }
+  }
+
+  const successful = results.filter((r) => r.ok);
+  const comparison = successful.length === 3 ? compareThree(successful.map((r) => r.normalized)) : null;
+
+  const verdict = {
+    schema: 'arc_triple_blind_report_v1',
+    mission_id: missionId,
+    run_id: runId,
+    created_at: new Date().toISOString(),
+    lanes: results.map((r) => ({
+      lane: r.lane,
+      provider: r.provider,
+      model: r.model,
+      ok: r.ok,
+      elapsed_ms: r.elapsed_ms,
+      error: r.error || null,
+      normalized: r.normalized || null,
+    })),
+    comparison,
+    chair_pass_by_convergence_rule: Boolean(comparison?.essentially_same),
+    rule: 'Chair PASS iff three independent architects produce essentially same blueprint',
+  };
+
+  const reportPath = path.join(outDir, 'ARC_TRIPLE_BLIND_REPORT.json');
+  writeJson(reportPath, verdict);
+  console.log(JSON.stringify({ ok: true, report_path: path.relative(REPO_ROOT, reportPath), verdict }, null, 2));
+  process.exit(comparison?.essentially_same ? 0 : 1);
+}
+
+main().catch((error) => {
+  console.error(error);
+  process.exit(1);
+});
